import React from 'react';

const Dealers = () => {
  return (
    <div style={{ marginTop: '50px' }}>
      <h2>Dealerships Dashboard</h2>
      <hr />
      <p>Welcome to the Dealership Home Page.</p>
      {/* This is where your dealership list will eventually be fetched */}
      <table className="table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>City</th>
            <th>State</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td colSpan="4">Fetching data from backend...</td>
          </tr>
        </tbody>
      </table>
    </div>
  );
};

export default Dealers;
